.darma-loader-darma-custom-414 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #f0abfc);
  width: 50px;
  aspect-ratio: 1.154;
  display: grid;
  color: var(--loader-color, #9333ea);
  background:linear-gradient(to bottom left ,#0000 calc(50% - 1px),currentColor 0 calc(50% + 1px),#0000 0) right/50% 100%,linear-gradient(to bottom right,#0000 calc(50% - 1px),currentColor 0 calc(50% + 1px),#0000 0) left /50% 100%,linear-gradient(currentColor 0 0) bottom/100% 2px;
  background-repeat: no-repeat;
  transform-origin: 50% 66%;
  animation: darma-loader-darma-custom-414-l5 4s infinite linear;
}.darma-loader-darma-custom-414::before,.darma-loader-darma-custom-414::after {content: "";
  grid-area: 1/1;
  background: inherit;
  transform-origin: inherit;
  animation: inherit;
}.darma-loader-darma-custom-414::after {animation-duration: 2s;
}@keyframes darma-loader-darma-custom-414-l5{100% {transform: rotate(1turn)}}

